import sys

def query(x, y):
    print(f"? {x} {y}")
    sys.stdout.flush()
    return int(sys.stdin.readline())

def find_base():
    low_x = 1
    high_x = 10**9
    low_y = 1
    high_y = 10**9

    # Find the left boundary
    left = low_x
    right = high_x
    while left < right:
        mid = (left + right) // 2
        d = query(mid, 1)
        if d == -1:
            right = mid - 1
        else:
            if d == mid - 1:
                right = mid
            else:
                left = mid + 1
    x_min = left

    # Find the right boundary
    left = low_x
    right = high_x
    while left < right:
        mid = (left + right + 1) // 2
        d = query(mid, 1)
        if d == -1:
            left = mid + 1
        else:
            if d == high_x - mid:
                left = mid
            else:
                right = mid - 1
    x_max = left

    # Find the bottom boundary
    left = low_y
    right = high_y
    while left < right:
        mid = (left + right) // 2
        d = query(1, mid)
        if d == -1:
            right = mid - 1
        else:
            if d == mid - 1:
                right = mid
            else:
                left = mid + 1
    y_min = left

    # Find the top boundary
    left = low_y
    right = high_y
    while left < right:
        mid = (left + right + 1) // 2
        d = query(1, mid)
        if d == -1:
            left = mid + 1
        else:
            if d == high_y - mid:
                left = mid
            else:
                right = mid - 1
    y_max = left

    print(f"! {x_min} {y_min} {x_max} {y_max}")
    sys.stdout.flush()

find_base()

